+fn indexed_column_collation(indexed_column: &IndexedColumn) -> Option<String> {
+    fn extract(expr: &Expr) -> Option<&str> {
+        match expr {
+            Expr::Collate {
+                expr, collation, ..
+            } => extract(expr).or(Some(collation.as_str())),
+            Expr::Column(..) => None,
+            _ => None,
+        }
+    }
+
+    indexed_column
+        .collation
+        .clone()
+        .or_else(|| extract(&indexed_column.expr).map(str::to_owned))
+}
